// src/modules/projects/routes.js
const express = require('express');
const router = express.Router();
const projectsService = require('../projects/service');
const { sendError } = require('../../lib/errors');

router.get('/', async (req, res) => {
  try {
    const projects = await projectsService.getAllProjects();
    res.json({ projects });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

router.get('/:projectId', async (req, res) => {
  try {
    const projectId = req.params.projectId;
    const project = await projectsService.getProjectById(projectId);
    if (!project) {
      return sendError(res, 404, 'PROJECT_NOT_FOUND', 'Project not found');
    }
    res.json({ project });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

router.post('/', async (req, res) => {
  try {
    const { name } = req.body;
    if (!name || typeof name !== 'string' || name.trim() === '') {
      return sendError(res, 400, 'INVALID_NAME', 'Invalid project name');
    }
    const newProject = await projectsService.createProject(name);
    res.status(201).json({ project: newProject });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

module.exports = router;

// src/modules/members/routes.js
const express = require('express');
const router = express.Router();
const membersService = require('../members/service');
const { sendError } = require('../../lib/errors');

router.get('/', async (req, res) => {
  try {
    const projectId = req.params.projectId;
    const members = await membersService.getAllMembers(projectId);
    res.json({ members });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

router.post('/', async (req, res) => {
  try {
    const { userId, role } = req.body;
    if (!userId || !role) {
      return sendError(res, 400, 'INVALID_INPUT', 'Invalid input');
    }
    const newMember = await membersService.addMember(req.params.projectId, userId, role);
    res.status(201).json({ member: newMember });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

module.exports = router;

// src/modules/tasks/routes.js
const express = require('express');
const router = express.Router();
const tasksService = require('../tasks/service');
const { sendError } = require('../../lib/errors');

router.get('/', async (req, res) => {
  try {
    const projectId = req.params.projectId;
    let tasks = await tasksService.getAllTasks(projectId);
    if (req.query.status === 'done') {
      tasks = tasks.filter(task => task.status === 'done');
    }
    res.json({ tasks });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

router.patch('/:taskId', async (req, res) => {
  try {
    const { status } = req.body;
    if (!['todo', 'done'].includes(status)) {
      return sendError(res, 400, 'INVALID_STATUS', 'Invalid task status');
    }
    const updatedTask = await tasksService.updateTaskStatus(req.params.projectId, req.params.taskId, status);
    if (!updatedTask) {
      return sendError(res, 404, 'TASK_NOT_FOUND', 'Task not found');
    }
    res.json({ task: updatedTask });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

module.exports = router;

// src/modules/comments/routes.js
const express = require('express');
const router = express.Router();
const commentsService = require('../comments/service');
const { sendError } = require('../../lib/errors');

router.get('/', async (req, res) => {
  try {
    const taskId = req.params.taskId;
    const comments = await commentsService.getAllComments(taskId);
    res.json({ comments });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

router.post('/', async (req, res) => {
  try {
    const { message } = req.body;
    if (!message || typeof message !== 'string' || message.trim() === '') {
      return sendError(res, 400, 'INVALID_MESSAGE', 'Invalid comment message');
    }
    const newComment = await commentsService.addComment(req.params.taskId, message);
    res.status(201).json({ comment: newComment });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Internal server error');
  }
});

module.exports = router;

// src/modules/projects/service.js
const { randomUUID } = require('node:crypto');

let projectsStore = [];

async function getAllProjects() {
  return projectsStore;
}

async function getProjectById(projectId) {
  return projectsStore.find(p => p.id === projectId);
}

async function createProject(name) {
  const newProject = { id: randomUUID(), name };
  projectsStore.push(newProject);
  return newProject;
}

module.exports = {
  getAllProjects,
  getProjectById,
  createProject,
};

// src/modules/members/service.js
const { randomUUID } = require('node:crypto');

let membersStore = [];

async function getAllMembers(projectId) {
  return membersStore.filter(m => m.projectId === projectId);
}

async function addMember(projectId, userId, role) {
  const newMember = { id: randomUUID(), projectId, userId, role };
  membersStore.push(newMember);
  return newMember;
}

module.exports = {
  getAllMembers,
  addMember,
};

// src/modules/tasks/service.js
const { randomUUID } = require('node:crypto');

let tasksStore = [];

async function getAllTasks(projectId) {
  return tasksStore.filter(t => t.projectId === projectId);
}

async function updateTaskStatus(projectId, taskId, status) {
  const taskIndex = tasksStore.findIndex(t => t.id === taskId && t.projectId === projectId);
  if (taskIndex === -1) {
    return null;
  }
  tasksStore[taskIndex].status = status;
  return tasksStore[taskIndex];
}

module.exports = {
  getAllTasks,
  updateTaskStatus,
};

// src/modules/comments/service.js
const { randomUUID } = require('node:crypto');

let commentsStore = [];

async function getAllComments(taskId) {
  return commentsStore.filter(c => c.taskId === taskId);
}

async function addComment(taskId, message) {
  const newComment = { id: randomUUID(), taskId, message };
  commentsStore.push(newComment);
  return newComment;
}

module.exports = {
  getAllComments,
  addComment,
};

// src/app.js
const express = require('express');
const projectsRouter = require('./modules/projects/routes');
const membersRouter = require('./modules/members/routes');
const tasksRouter = require('./modules/tasks/routes');
const commentsRouter = require('./modules/comments/routes');

const app = express();
app.use(express.json());

app.get('/health', (req, res) => {
  res.status(200).json({ status: 'OK' });
});

app.use('/projects/:projectId/members', membersRouter);
app.use('/projects/:projectId/tasks', tasksRouter);
app.use('/tasks/:taskId/comments', commentsRouter);
app.use('/projects', projectsRouter);

module.exports = app;
